css:
[data-scheme="lcars"] {
	font-family: 'Arial Narrow', 'Arial', Helvetica, sans-serif;
	text-transform: uppercase;
	letter-spacing: 1px;
}

[data-scheme="lcars"] .w-64 {
	width: 22rem;
}

[data-scheme="lcars"] aside {
	position: relative;
	border-color: transparent !important;
	padding: 15px;
	overflow: hidden;
}

[data-scheme="lcars"] aside::before {
	content: '';
	position: absolute;
	top: 15px;
	left: 15px;
	right: 15px;
	height: 60px;
	z-index: 10;
	border-radius: 40px 0 0 0;
	background: linear-gradient(to right, #c9c 0, #c9c 100px, transparent 100px, transparent 115px, #c9c 115px);
}

[data-scheme="lcars"] aside [data-logo] {
	display: flex !important;
	position: absolute;
	top: 12px;
	left: 14px;
	z-index: 15;
	padding: 0;
	width: auto;
	height: auto;
	align-items: center;
	justify-content: center;
}

[data-scheme="lcars"] aside [data-logo] img {
	height: 32px !important;
	width: 32px !important;
}

[data-scheme="lcars"] aside::after {
	content: '';
	position: absolute;
	top: 79px;
	left: 15px;
	bottom: 79px;
	width: 100px;
	z-index: 10;
	background:
		linear-gradient(to bottom,
			#c9c 0, #c9c 15px,
			transparent 15px, transparent 20px,
			#f90 20px, #f90 120px,
			transparent 120px, transparent 125px,
			#fca 125px, #fca 180px,
			transparent 180px, transparent 185px,
			#99f 185px, #99f 300px,
			transparent 300px, transparent 305px,
			#fc3 305px
		);
}

[data-scheme="lcars"] aside > div::after {
	content: '';
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 60px;
	z-index: 10;
	border-radius: 0 0 0 40px;
	background: linear-gradient(to right, #fc3 0, #fc3 100px, transparent 100px, transparent 115px, #fc3 115px);
}

[data-scheme="lcars"] aside > div {
	position: relative;
	z-index: 11;
	padding-left: 105px;
	padding-top: 70px;
	padding-bottom: 70px;
}

[data-scheme="lcars"] aside hr {
	display: none;
}

[data-scheme="lcars"] aside nav a[href] {
	background: #99f;
	color: #000 !important;
	font-weight: bold;
	font-size: 0.85rem;
	letter-spacing: 0.1em;
	border-radius: 20px;
	text-align: right;
	justify-content: flex-end;
	padding: 0.5rem 1rem;
	margin: 3px 0;
	transition: all 0.2s;
}

[data-scheme="lcars"] aside nav a[href] svg {
	display: none;
}

[data-scheme="lcars"] aside nav a[href]:hover {
	background: #fff !important;
	color: #000 !important;
	transform: translateX(5px);
}

[data-scheme="lcars"] aside nav a[href][data-active="true"] {
	background: #fca !important;
	color: #000 !important;
}

[data-scheme="lcars"] aside nav a[href]:nth-child(2) {
	background: #fca;
}

[data-scheme="lcars"] aside nav a[href]:nth-child(3) {
	background: #f90;
}

[data-scheme="lcars"] aside nav a[href]:nth-child(4) {
	background: #c9c;
}

[data-scheme="lcars"] aside [data-stats] {
	border-top: 4px solid #f90 !important;
	border-left: none !important;
	border-right: none !important;
	border-bottom: none !important;
	background: transparent;
	padding-top: 0.75rem;
}

[data-scheme="lcars"] aside [data-stats] .flex.rounded {
	background: #222 !important;
	border-radius: 20px !important;
	padding: 3px !important;
	gap: 3px;
}

[data-scheme="lcars"] aside [data-stats] .flex.rounded > button {
	border-radius: 20px !important;
	color: #000 !important;
	background: #666 !important;
	font-weight: bold !important;
	padding: 0.25rem 0.75rem !important;
}

[data-scheme="lcars"] aside [data-stats] .flex.rounded > button.bg-primary\/20,

[data-scheme="lcars"] aside [data-stats] .flex.rounded > button.dark\:bg-primary\/25 {
	background: #f90 !important;
	color: #000 !important;
}

[data-scheme="lcars"] [data-progress-track] {
	background: #222 !important;
	border-radius: 0 6px 6px 0 !important;
	height: 12px !important;
}

[data-scheme="lcars"] [data-progress-fill] {
	border-radius: 0 !important;
	background: #f90 !important;
	animation: lcars-scan 2s infinite ease-in-out;
}

[data-scheme="lcars"] [data-stats] .space-y-2 > div:nth-child(1) [data-progress-fill] {
	background: #f90 !important;
}

[data-scheme="lcars"] [data-stats] .space-y-2 > div:nth-child(2) [data-progress-fill] {
	background: #99f !important;
}

[data-scheme="lcars"] [data-stats] .mt-3 [data-progress-fill] {
	background: #c9c !important;
}

[data-scheme="lcars"] aside .text-gray-400,

[data-scheme="lcars"] aside .text-gray-500,

[data-scheme="lcars"] aside .text-gray-600,

[data-scheme="lcars"] aside .dark\:text-gray-300,

[data-scheme="lcars"] aside .dark\:text-gray-400,

[data-scheme="lcars"] aside .dark\:text-gray-500 {
	color: #fca !important;
	letter-spacing: 0.1em;
	font-weight: bold;
}

[data-scheme="lcars"] aside .text-orange-500 {
	color: #ff8b8b !important;
}

[data-scheme="lcars"] body {
	background: #000 !important;
	color: #fff !important;
}

[data-scheme="lcars"] .flex.h-screen > div.flex-1 {
